package com.vidaysalud.veterinaria.citaservicio.service;import com.vidaysalud.veterinaria.citaservicio.client.*;import com.vidaysalud.veterinaria.citaservicio.dto.*;import com.vidaysalud.veterinaria.citaservicio.exception.*;import com.vidaysalud.veterinaria.citaservicio.model.*;import com.vidaysalud.veterinaria.citaservicio.repository.CitaRepository;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;@Service @RequiredArgsConstructor @Slf4j @Transactional public class CitaService{private final CitaRepository r;private final MascotaClient mascota;private final VeterinarioClient veterinario;@Transactional(readOnly=true)public List<CitaResponseDTO>listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public CitaResponseDTO buscar(Integer id){return dto(get(id));}@Transactional(readOnly=true)public List<CitaResponseDTO>porMascota(Integer id){return r.findByIdMascota(id).stream().map(this::dto).toList();}public CitaResponseDTO crear(CitaRequestDTO d){validarRemoto(d);validarHorario(d.getIdVeterinario(),d.getFechaHora());Cita c=map(new Cita(),d);return dto(r.save(c));}public CitaResponseDTO actualizar(Integer id,CitaRequestDTO d){validarRemoto(d);Cita c=get(id);if(!c.getFechaHora().equals(d.getFechaHora())||!c.getIdVeterinario().equals(d.getIdVeterinario()))validarHorario(d.getIdVeterinario(),d.getFechaHora());return dto(r.save(map(c,d)));}public CitaResponseDTO estado(Integer id,EstadoCita e){Cita c=get(id);if(c.getEstado()==EstadoCita.Atendida&&e==EstadoCita.Cancelada)throw new ReglaNegocioException("Una cita atendida no puede cancelarse");c.setEstado(e);return dto(r.save(c));}public void eliminar(Integer id){r.delete(get(id));}private void validarRemoto(CitaRequestDTO d){mascota.validar(d.getIdMascota());veterinario.validar(d.getIdVeterinario());if(d.getFechaHora().isBefore(LocalDateTime.now()))throw new ReglaNegocioException("La cita debe ser futura");}private void validarHorario(Integer v,LocalDateTime f){if(r.existsByIdVeterinarioAndFechaHoraAndEstadoNot(v,f,EstadoCita.Cancelada))throw new DatoDuplicadoException("El veterinario ya posee una cita en ese horario");}private Cita get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Cita no encontrada: "+id));}private Cita map(Cita c,CitaRequestDTO d){c.setIdMascota(d.getIdMascota());c.setIdVeterinario(d.getIdVeterinario());c.setFechaHora(d.getFechaHora());c.setEstado(d.getEstado()==null?EstadoCita.Pendiente:d.getEstado());c.setMotivo(d.getMotivo().trim());c.setObservaciones(d.getObservaciones());return c;}private CitaResponseDTO dto(Cita c){return CitaResponseDTO.builder().idCita(c.getIdCita()).idMascota(c.getIdMascota()).idVeterinario(c.getIdVeterinario()).fechaHora(c.getFechaHora()).estado(c.getEstado()).motivo(c.getMotivo()).observaciones(c.getObservaciones()).fechaCreacion(c.getFechaCreacion()).build();}}